+    fn client_reply_rejects_invalid_mode_and_extra_arguments() {
+        let mut store = Store::new();
+        let err = dispatch_argv(
+            &[b"CLIENT".to_vec(), b"REPLY".to_vec(), b"MAYBE".to_vec()],
+            &mut store,
+            0,
+        )
+        .unwrap_err();
+        assert_eq!(err, CommandError::SyntaxError);
