+        let err = dispatch_argv(
+            &[
+                b"CLIENT".to_vec(),
+                b"REPLY".to_vec(),
+                b"ON".to_vec(),
+                b"NOW".to_vec(),
+            ],
+            &mut store,
+            0,
+        )
+        .unwrap_err();
